using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;

    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    Ptr sketchCircles = curves->sketchCircles();
    if (!sketchCircles)
        return false;

    Ptr centerPoint = adsk::core::Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    sketchCircles->addByCenterRadius(centerPoint, 5.0);

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;

    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;

    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;

    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;

    extInput->setDistanceExtent(false, distance);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get end faces
    Ptr endFacesObj = ext->endFaces();
    if (!endFacesObj)
        return false;
    Ptr endFace = endFacesObj->item(0);
    if (!endFace)
        return false;

    // Create SurfaceDeleteFaceFeature
    Ptr surfaceDeleteFaceFeaturesObj = feats->surfaceDeleteFaceFeatures();
    if (!surfaceDeleteFaceFeaturesObj)
        return false;
    Ptr surfaceDeleteFaceFeature = surfaceDeleteFaceFeaturesObj->add(endFace);
    if (!surfaceDeleteFaceFeature)
        return false;


    return true;
}
